# .NET 10 AI Agent APIs - Comprehensive Reference

## Overview
I've analyzed both NuGet packages for building AI agents in .NET 10. Here's the complete API landscape:

## 1. **Microsoft.Extensions.AI.Abstractions (v10.4.1)** 
Core abstractions for AI services in .NET.

### Key Interfaces & Classes

#### **IChatClient** - Main AI Service Interface
```csharp
public interface IChatClient
{
    // Send messages and get response
    Task<ChatResponse> GetResponseAsync(
        IEnumerable<ChatMessage> messages,
        ChatOptions options,
        CancellationToken cancellationToken);

    // Stream response updates
    IAsyncEnumerable<ChatResponseUpdate> GetStreamingResponseAsync(
        IEnumerable<ChatMessage> messages,
        ChatOptions options,
        CancellationToken cancellationToken);

    // Get optional services (like metadata)
    TService? GetService<TService>(object? key = null);
}
```

#### **ChatMessage** - Message Structure
```csharp
public struct ChatMessage
{
    public ChatMessage();
    public ChatMessage(ChatRole role, string content);
    public ChatMessage(ChatRole role, IList<AIContent> contents);

    public ChatRole Role { get; set; }
    public IList<AIContent> Contents { get; set; }

    public ChatMessage Clone();
}

public enum ChatRole
{
    User,
    Assistant,
    System,
    Tool
}
```

#### **ChatOptions** - Configuration for Chat Requests
```csharp
public class ChatOptions
{
    public string? ConversationId { get; set; }
    public string? Instructions { get; set; }
    public double? Temperature { get; set; }
    public int? MaxOutputTokens { get; set; }
    public double? TopP { get; set; }
    public ChatToolMode? ToolMode { get; set; }
    public IList<AITool>? Tools { get; set; }
    public ChatResponseFormat? ResponseFormat { get; set; }
    public ReasoningOptions? ReasoningOptions { get; set; }
    public bool AllowBackgroundResponses { get; set; }
    public bool AllowMultipleToolCalls { get; set; }
}
```

#### **ChatResponse** - Chat Service Response
```csharp
public class ChatResponse
{
    public ChatResponse();
    public ChatResponse(ChatMessage message);

    public IList<ChatMessage> Messages { get; }
    public int? InputTokenCount { get; set; }
    public int? OutputTokenCount { get; set; }
    public ChatFinishReason? FinishReason { get; set; }
    public string? ModelId { get; set; }
    public string? ConversationId { get; set; }
}

public enum ChatFinishReason
{
    Stop,
    ToolCalls,
    Length,
    ContentFilter,
    Error
}
```

#### **AIContent** - Message Content Types
```csharp
// Base class for all content
public abstract class AIContent { }

// Concrete types:
public class TextContent : AIContent
{
    public string Text { get; set; }
}

public class FunctionCallContent : AIContent
{
    public string CallId { get; set; }
    public string Name { get; set; }
    public IDictionary<string, object>? Arguments { get; set; }
}

public class FunctionResultContent : AIContent
{
    public string CallId { get; set; }
    public object? Result { get; set; }
    public string? ResultType { get; set; }
}

public class ToolApprovalRequestContent : AIContent
{
    public FunctionCallContent FunctionCall { get; set; }
}

public class ToolApprovalResponseContent : AIContent
{
    public string RequestId { get; set; }
    public bool Approved { get; set; }
}

// Other types: DataContent, ErrorContent, UriContent, HostedFileContent, UsageContent, etc.
```

### Function/Tool Definitions

#### **AITool** - Tool Specification
```csharp
public class AITool
{
    public string Name { get; }
    public string Description { get; }
    public IDictionary<string, object>? AdditionalProperties { get; }
}
```

#### **AIFunctionDeclaration** - Function Description (no invocation)
```csharp
public class AIFunctionDeclaration : AITool
{
    public JsonElement JsonSchema { get; set; }
    public JsonElement? ReturnJsonSchema { get; set; }
}
```

#### **AIFunction** - Invocable Function
```csharp
public abstract class AIFunction : AIFunctionDeclaration
{
    public MethodInfo? UnderlyingMethod { get; }
    public JsonSerializerOptions JsonSerializerOptions { get; }

    // Invoke the function
    public Task<object?> InvokeAsync(
        AIFunctionArguments arguments,
        CancellationToken cancellationToken);

    // Declaration-only version (no invocation)
    public AIFunctionDeclaration AsDeclarationOnly();
}
```

#### **AIFunctionArguments** - Function Call Parameters
```csharp
public class AIFunctionArguments : IDictionary<string, object>
{
    public AIFunctionArguments();
    public AIFunctionArguments(IDictionary<string, object> arguments);

    // From IDictionary<string, object>
    public void Add(string key, object value);
    public bool TryGetValue(string key, out object value);
    public object this[string key] { get; set; }

    // Additional properties
    public IServiceProvider? Services { get; set; }
    public object? Context { get; set; }
}
```

#### **AIFunctionFactory** - Creates Functions from Reflection
```csharp
public static class AIFunctionFactory
{
    // Create from delegate
    public static AIFunction Create(
        Delegate @delegate,
        AIFunctionFactoryOptions? options = null);

    // Create from method
    public static AIFunction Create(
        MethodInfo method,
        object? instance,
        AIFunctionFactoryOptions? options = null);

    // Create declaration only
    public static AIFunctionDeclaration CreateDeclaration(
        string name,
        string description,
        JsonElement jsonSchema,
        JsonElement? returnJsonSchema = null);
}

public class AIFunctionFactoryOptions
{
    public JsonSerializerOptions SerializerOptions { get; set; }
    public string? Name { get; set; }
    public string? Description { get; set; }
    public Action<ParameterBindingOptions>? ConfigureParameterBinding { get; set; }
}
```

#### **ApprovalRequiredAIFunction** - Functions Requiring User Approval
```csharp
public class ApprovalRequiredAIFunction : AIFunction
{
    // Wraps another AIFunction and requires approval before invocation
}
```

### Tool Modes

```csharp
public abstract class ChatToolMode { }
public class AutoChatToolMode : ChatToolMode { }      // Auto-invoke tools
public class RequiredChatToolMode : ChatToolMode { }  // Must use tools
public class NoneChatToolMode : ChatToolMode { }      // No tool calling
```

---

## 2. **Microsoft.Extensions.AI (v10.4.1)**
Higher-level utilities and middleware for building AI pipelines.

### ChatClientBuilder - Pipeline Pattern

```csharp
public class ChatClientBuilder
{
    // Create with inner client
    public ChatClientBuilder(IChatClient innerClient);
    public ChatClientBuilder(Func<IServiceProvider, IChatClient> innerClientFactory);

    // Add middleware
    public ChatClientBuilder Use(Func<IChatClient, IChatClient> clientFactory);
    public ChatClientBuilder Use(Func<IChatClient, IServiceProvider, IChatClient> clientFactory);
    public ChatClientBuilder Use(
        Func<IEnumerable<ChatMessage>, ChatOptions, 
            Func<...>, CancellationToken, Task> sharedFunc);

    // Build the pipeline
    public IChatClient Build(IServiceProvider? services = null);
}

// Extension: Create builder from IChatClient
public static ChatClientBuilder AsBuilder(this IChatClient innerClient);
```

### Middleware Classes (Delegating Chat Clients)

```csharp
// Automatic function invocation
public class FunctionInvokingChatClient : DelegatingChatClient
{
    public int MaximumIterationsPerRequest { get; set; } = 10;
    public int MaximumConsecutiveErrorsPerRequest { get; set; } = 3;
    public IList<AITool>? AdditionalTools { get; set; }
    public bool TerminateOnUnknownCalls { get; set; }
    public bool AllowConcurrentInvocation { get; set; }

    // Called when function invocation occurs
    public Func<FunctionInvocationContext, CancellationToken, ValueTask<object?>>? FunctionInvoker { get; set; }
}

// Logging
public class LoggingChatClient : DelegatingChatClient { }

// OpenTelemetry
public class OpenTelemetryChatClient : DelegatingChatClient { }

// Caching
public class CachingChatClient : DelegatingChatClient { }
public class DistributedCachingChatClient : DelegatingChatClient { }

// Response reduction/summarization
public class ReducingChatClient : DelegatingChatClient { }
public class SummarizingChatReducer : IChatReducer { }

// Image generation
public class ImageGeneratingChatClient : DelegatingChatClient { }

// Configure options per request
public class ConfigureOptionsChatClient : DelegatingChatClient { }
```

### Extension Methods for Building

```csharp
// FunctionInvokingChatClientBuilderExtensions
public static ChatClientBuilder UseFunctionInvocation(
    this ChatClientBuilder builder,
    ILoggerFactory? loggerFactory = null,
    Action<FunctionInvokingChatClient>? configure = null);

// OpenTelemetryChatClientBuilderExtensions
public static ChatClientBuilder UseOpenTelemetry(
    this ChatClientBuilder builder,
    ILoggerFactory? loggerFactory = null,
    string? modelId = null,
    Action<OpenTelemetryChatClient>? configure = null);

// LoggingChatClientBuilderExtensions
public static ChatClientBuilder UseLogging(
    this ChatClientBuilder builder,
    ILoggerFactory? loggerFactory = null);

// CachingChatClientBuilderExtensions (and Distributed variants)
public static ChatClientBuilder UseCaching(
    this ChatClientBuilder builder);

// And many more...
```

### Function Invocation Context

```csharp
public class FunctionInvocationContext
{
    public AIFunction Function { get; }
    public FunctionCallContent CallContent { get; }
    public AIFunctionArguments Arguments { get; }
    public int AttemptCount { get; }
    public string ConversationId { get; }
}

public class FunctionInvocationProcessor
{
    // Process multiple function calls
    public Task ProcessFunctionCallsAsync(
        List<FunctionCallContent> functionCalls,
        Func<string, AITool> toolProvider,
        bool allowConcurrentInvocation,
        Func<FunctionCallContent, AIFunction, int, FunctionInvocationContext> contextFactory,
        Action<FunctionInvocationContext> preInvoke,
        bool includeDetailedErrors,
        CancellationToken cancellationToken);
}
```

