## 3. **Microsoft.Agents.AI.Abstractions (v1.0.0)**
Abstractions for building multi-agent systems.

### Core Agent Types

#### **AIAgent** - Base Agent Class
```csharp
public abstract class AIAgent
{
    public string Id { get; }
    public string Name { get; set; }
    public string Description { get; set; }
    public AIAgentMetadata Metadata { get; }
    public AgentRunContext? CurrentRunContext { get; }

    // Core run method (multiple overloads)
    public Task<AgentResponse> RunAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession? session = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default);

    public Task<AgentResponse> RunAsync(
        string message,
        AgentSession? session = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default);

    public Task<AgentResponse> RunAsync(
        ChatMessage message,
        AgentSession? session = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default);

    // Streaming version
    public IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession? session = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default);

    // Generic structured output versions
    public Task<AgentResponse<T>> RunAsync<T>(
        IEnumerable<ChatMessage> messages,
        JsonSerializerOptions? jsonSerializerOptions = null,
        AgentSession? session = null,
        AgentRunOptions? options = null,
        CancellationToken cancellationToken = default);
}

public class AgentResponse
{
    public IList<ChatMessage> Messages { get; }
    public string Text { get; }  // Convenience property
    public object? RawRepresentation { get; set; }
}

public class AgentResponseUpdate
{
    public ChatResponseUpdate Update { get; }
}
```

#### **AgentSession** - Conversation State
```csharp
public class AgentSession
{
    public string ConversationId { get; }
    public string? UserId { get; set; }
    public IList<ChatMessage> History { get; }
    public AgentSessionStateBag State { get; }  // Custom state storage
}

public class AgentSessionStateBag : IDictionary<string, object>
{
    // Full dictionary interface for custom data storage
}
```

#### **AgentRunContext** - In-Flight Run Info
```csharp
public class AgentRunContext
{
    public AIAgent Agent { get; }
    public AgentSession Session { get; }
    public IReadOnlyCollection<ChatMessage> RequestMessages { get; }
    public AgentRunOptions RunOptions { get; }
    public AgentResponse? Response { get; }
}
```

#### **AgentRunOptions** - Configuration
```csharp
public class AgentRunOptions
{
    public string? Instructions { get; set; }
    public int? MaximumIterations { get; set; }
    public CancellationToken CancellationToken { get; set; }
}
```

### Context Providers

```csharp
// Provide dynamic context to agents
public abstract class AIContextProvider
{
    public string Name { get; }

    // Called before agent invocation
    public ValueTask OnInvokingAsync(InvokingContext context);

    // Called after agent invocation
    public ValueTask OnInvokedAsync(InvokedContext context);
}

public class MessageAIContextProvider : AIContextProvider
{
    // Injects messages/context into the conversation
}
```

