var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Please set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build the IChatClient from the OpenAI SDK
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIChatClient(
    new OpenAIClient(apiKey).GetChatClient(modelId));

// ---------------------------------------------------------------------------
// Shared state for the note-taking tool
// ---------------------------------------------------------------------------
var notebook = new List<ResearchNote>();

// ---------------------------------------------------------------------------
// Define the tools the agent can use
// ---------------------------------------------------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWebAsync, "web_search",
        "Search the web for information on a topic. Returns relevant text snippets."),

    AIFunctionFactory.Create(SaveNote, "save_note",
        "Save a research note with a title and content for later reference."),

    AIFunctionFactory.Create(GetNotes, "get_notes",
        "Retrieve all research notes saved so far."),
};

// ---------------------------------------------------------------------------
// Create the ChatClientAgent
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic you MUST:
        1. Use the web_search tool multiple times (at least 3 searches) to explore
           different angles, subtopics, and recent developments.
        2. After each search, save the most important findings using the save_note tool.
        3. Once you have gathered enough information, call get_notes to review everything.
        4. Finally, produce a well-structured summary with sections, key facts, and
           takeaways. Cite the search queries you used.
        Be factual, concise, and organize your summary with clear headings.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔═══════════════════════════════════════╗");
Console.WriteLine("║       🔬  AI Research Agent  🔬       ║");
Console.WriteLine("║  Type a topic to research, or 'quit'  ║");
Console.WriteLine("╚═══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic ▸ ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
        topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine($"\n🔍 Researching: {topic}\n");

    try
    {
        var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session);

        Console.WriteLine();
        Console.WriteLine("═══════════════════════════════════════");
        Console.WriteLine("  📄 RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════");
        Console.WriteLine(response.Text);

        if (notebook.Count > 0)
        {
            Console.WriteLine();
            Console.WriteLine("═══════════════════════════════════════");
            Console.WriteLine($"  🗂️  RESEARCH NOTES ({notebook.Count} saved)");
            Console.WriteLine("═══════════════════════════════════════");
            for (var i = 0; i < notebook.Count; i++)
            {
                Console.WriteLine($"\n  [{i + 1}] {notebook[i].Title}");
                Console.WriteLine($"      {notebook[i].Content}");
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n❌ Error: {ex.Message}");
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// ═══════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

async Task<string> SearchWebAsync(
    [Description("The search query to look up")] string query,
    [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await http.GetStringAsync(url);

        var results = new List<string>();

        // Extract result snippets from DuckDuckGo HTML results
        foreach (Match m in Regex.Matches(html,
            @"class=""result__snippet""[^>]*>(.*?)</",
            RegexOptions.Singleline))
        {
            var text = StripHtml(m.Groups[1].Value);
            if (!string.IsNullOrWhiteSpace(text))
                results.Add(text);
            if (results.Count >= maxResults) break;
        }

        // Fallback: try result__a (titles) if no snippets found
        if (results.Count == 0)
        {
            foreach (Match m in Regex.Matches(html,
                @"class=""result__a""[^>]*>(.*?)</a>",
                RegexOptions.Singleline))
            {
                var text = StripHtml(m.Groups[1].Value);
                if (!string.IsNullOrWhiteSpace(text))
                    results.Add(text);
                if (results.Count >= maxResults) break;
            }
        }

        if (results.Count > 0)
        {
            Console.WriteLine($"     ✓ Found {results.Count} result(s)");
            return $"Search results for '{query}':\n" +
                   string.Join("\n---\n",
                       results.Select((r, i) => $"{i + 1}. {r}"));
        }

        Console.WriteLine("     ⚠ No results found");
        return $"No results found for '{query}'. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        Console.WriteLine($"     ⚠ Search error: {ex.Message}");
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

string SaveNote(
    [Description("A short descriptive title for the note")] string title,
    [Description("The content/body of the research note")] string content)
{
    notebook.Add(new ResearchNote(title, content));
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note '{title}' saved successfully. You now have {notebook.Count} note(s).";
}

string GetNotes()
{
    if (notebook.Count == 0)
        return "No notes have been saved yet.";

    Console.WriteLine($"  📋 Reviewing {notebook.Count} note(s)");
    return string.Join("\n\n", notebook.Select((n, i) =>
        $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
}

static string StripHtml(string html)
{
    var text = Regex.Replace(html, "<[^>]+>", " ");
    text = WebUtility.HtmlDecode(text);
    return Regex.Replace(text, @"\s+", " ").Trim();
}

// ═══════════════════════════════════════════════════════════════════════════
// Types
// ═══════════════════════════════════════════════════════════════════════════

record ResearchNote(string Title, string Content);

