 async Task<string> SearchWebAsync(
     [Description("The search query to look up")] string query,
     [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     using var http = new HttpClient();
     http.DefaultRequestHeaders.UserAgent.ParseAdd(
         "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
     http.Timeout = TimeSpan.FromSeconds(15);

     try
     {
         var encoded = WebUtility.UrlEncode(query);
         var url = $"https://html.duckduckgo.com/html/?q={encoded}";
         var html = await http.GetStringAsync(url);

         var results = new List<string>();

         // Extract result snippets from DuckDuckGo HTML results
         foreach (Match m in Regex.Matches(html,
             @"class=""result__snippet""[^>]*>(.*?)</",
             RegexOptions.Singleline))
         {
             var text = StripHtml(m.Groups[1].Value);
             if (!string.IsNullOrWhiteSpace(text))
                 results.Add(text);
             if (results.Count >= maxResults) break;
         }

         // Fallback: try result__a (titles) if no snippets found
         if (results.Count == 0)
         {
             foreach (Match m in Regex.Matches(html,
                 @"class=""result__a""[^>]*>(.*?)</a>",
                 RegexOptions.Singleline))
             {
                 var text = StripHtml(m.Groups[1].Value);
                 if (!string.IsNullOrWhiteSpace(text))
                     results.Add(text);
                 if (results.Count >= maxResults) break;
             }
         }

         if (results.Count > 0)
         {
             Console.WriteLine($"     ✓ Found {results.Count} result(s)");
             return $"Search results for '{query}':\n" +
                    string.Join("\n---\n",
                        results.Select((r, i) => $"{i + 1}. {r}"));
         }

         Console.WriteLine("     ⚠ No results found");
         return $"No results found for '{query}'. Try rephrasing the query.";
     }
     catch (Exception ex)
     {
         Console.WriteLine($"     ⚠ Search error: {ex.Message}");
         return $"Search failed: {ex.Message}. Try a different query.";
     }
 }

 string SaveNote(
     [Description("A short descriptive title for the note")] string title,
     [Description("The content/body of the research note")] string content)
 {
     notebook.Add(new ResearchNote(title, content));
     Console.WriteLine($"  📝 Note saved: \"{title}\"");
     return $"Note '{title}' saved successfully. You now have {notebook.Count} note(s).";
 }

 string GetNotes()
 {
     if (notebook.Count == 0)
         return "No notes have been saved yet.";

     Console.WriteLine($"  📋 Reviewing {notebook.Count} note(s)");
     return string.Join("\n\n", notebook.Select((n, i) =>
         $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
 }

 static string StripHtml(string html)
 {
     var text = Regex.Replace(html, "<[^>]+>", " ");
     text = WebUtility.HtmlDecode(text);
     return Regex.Replace(text, @"\s+", " ").Trim();
 }

